import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote - base premiums and processing fee
  it.todo("empty item list yields premium of just the 5 G processing fee");
  it.todo("a plain sword (no modifiers, no customer history) yields 100 G + 10 G first insurance + 5 G fee = 115 G");
  it.todo("a plain amulet yields 60 G + 6 G first insurance + 5 G fee = 71 G");
  it.todo("a plain staff yields 80 G + 8 G first insurance + 5 G fee = 93 G");
  it.todo("a plain potion yields 40 G + 4 G first insurance + 5 G fee = 49 G");

  // Components and block discount
  it.todo("a single rune yields 25 G base + 3 G first insurance (rounded up) + 5 G fee = 33 G");
  it.todo("2 runes yield 50 G base + 5 G first insurance + 5 G fee = 60 G");
  it.todo("3 runes form a block: 60 G base + 6 G first insurance + 5 G fee = 71 G");
  it.todo("4 runes: no block, 100 G base + 10 G first insurance + 5 G fee = 115 G");
  it.todo("7 runes: only one block of 3, 60 G + 4*25 G = 160 G base + 16 G first insurance + 5 G fee = 181 G");
  it.todo("2 runes + 1 moonstone: no block (different types) = 75 G base + 8 G first insurance (rounded up) + 5 G fee = 88 G");
  it.todo("3 runes + 3 moonstones: two separate blocks = 120 G base + 12 G first insurance + 5 G fee = 137 G");

  // Item-level modifiers
  it.todo("a cursed sword: 100 G + 50 G cursed surcharge + 15 G first insurance + 5 G fee = 170 G");
  it.todo("a sword with enchantment 5: 100 G + 30 G high-enchantment + 13 G first insurance + 5 G fee = 148 G");
  it.todo("a sword with enchantment 4: no high-enchantment surcharge, 100 G + 10 G first + 5 G fee = 115 G");
  it.todo("a cursed sword with enchantment 5: 100 G + 50 G + 30 G + 18 G first insurance + 5 G fee = 203 G");

  // Policy-wide modifiers
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("first-ever contract: only first insurance surcharge applies (no follow-up discount)");
  it.todo("second contract in the scenario: follow-up contract -15% applies");
  it.todo("multi-item policy: item-specific modifier applies only to that item's base premium");

  // Rounding
  it.todo("premium with fractional result is rounded UP (in MHPCO's favor)");

  // Integration examples from spec
  it.todo("newcomer (0 years) with a cursed sword yields 165 G");
  it.todo("long-standing customer's (3 years) second contract: cursed sword enchantment 7 yields 160 G");

  // Claim processing - basic
  it.todo("standard sword damage: 500 G damage on insured sword yields payout 400 G (after 100 G deductible)");
  it.todo("damage to a rune (250 G insurance value, 200 G damage) yields payout 100 G");

  // Claim - enchantment threshold
  it.todo("dragon-material sword at exactly enchantment 8, damage 1000 G: payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G: payout 400 G");
  it.todo("dragon-material sword enchantment 5, damage 800 G: payout 700 G (full reimbursement, deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G: payout 400 G");

  // Claim - multiple damages
  it.todo("two damaged items: deductible applies once per damage (sword 500 + amulet 300 = 600 G payout)");

  // Cap
  it.todo("cap exhaustion: sword (cap 2000), two 1500 G claims yield payouts 1400 and 600 G");

  // Validation/errors
  it.todo("quote with unknown item type causes CLI non-zero exit and stderr message");
  it.todo("claim with item type not in policy causes CLI non-zero exit");
  it.todo("claim with negative damage amount causes CLI non-zero exit");
  it.todo("claim with more damage entries of a type than policy covers causes CLI non-zero exit");
});

