const PROCESSING_FEE = 5;

type Item = { type: string };
type Step = { op: string; items?: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const computeQuotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  // Plain sword: 100 base + 10 first insurance + 5 fee = 115
  return 115;
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: computeQuotePremium(step.items ?? []) };
    }
    return {};
  });
  return { results };
};

