  it.todo("dragon-material sword at exactly enchantment 8, damage 1000 G: payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G: payout 400 G");
  it.todo("dragon-material sword enchantment 5, damage 800 G: payout 700 G (full reimbursement, deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G: payout 400 G");

