const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };
type Step = { op: string; items?: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const computeItemBasePremium = (items: Item[]): number => {
  let basePremium = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      basePremium += BASE_PREMIUM[item.type];
    }
  }
  for (const count of Object.values(componentCounts)) {
    if (count === COMPONENT_BLOCK_SIZE) {
      basePremium += COMPONENT_BLOCK_PREMIUM;
    } else {
      basePremium += count * BASE_PREMIUM["rune"];
    }
  }
  return basePremium;
};

const computeQuotePremium = (items: Item[]): number => {
  const basePremium = computeItemBasePremium(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: computeQuotePremium(step.items ?? []) };
    }
    return {};
  });
  return { results };
};

